import React from 'react';
import { Link } from 'react-router-dom';


const artNav = {
    display: 'inline-block',
    fontFamily: 'Bangers',
    textShadow: '0.1em 0.1em 0.1em #000',
    color: '#879cfa',
    padding: '5%',
    margin: '5%'
}

export class ArtNav extends React.Component{

    render(){
      
        return(
                 <div className="art-nav">             
                     <Link className="artBtn" to="/portfolio/Artwork/Vector" style={artNav}>Vector</Link>
                     <Link className="artBtn" to="/PenAndInk" style={artNav}>Pen/ink</Link>
                     <Link className="artBtn" to="/Books" style={artNav}>Books</Link>
                 </div>
        )
    }
}
export default ArtNav;