import React from 'react';

const videoLayout = {
    display: 'grid',
    gridTemplateColumns: '1fr 1fr',
    alignItems: 'center',
    gridGap: '0.5rem',
    margin: '10%'
}

    class Animation extends React.Component{
    
        render() {

            return (
            <div>
                <figure style={videoLayout} className="video-gallery">
                        <iframe title="2d animation" className="video-gallery-link"  src="https://www.youtube.com/embed/1VrP5lbTfOk" frameBorder="0" allow="accelerometer; autoplay; encrypted-media; gyroscope; picture-in-picture" allowFullScreen></iframe> 
                        <iframe title="2d animation" className="video-gallery-link"  src="https://www.youtube.com/embed/V6Fn7a0bDj0" frameBorder="0" allow="accelerometer:autoplay;encrypted-media; gyroscope; picture-in-picture" allowFullScreen></iframe>   
                        <iframe title="2d animation" className="video-gallery-link"  src="https://www.youtube.com/embed/nknhlceyMG0?list=PLNxnf4DQ_ssa5IPk4egFaHtJ9zA3J8U78" frameBorder="0" allow="accelerometer:autoplay;encrypted-media; gyroscope; picture-in-picture" allowFullScreen></iframe>
                        <iframe title="2d animation" className="video-gallery-link"  src="https://www.youtube.com/embed/SQ4zfA-Kqic?list=PLNxnf4DQ_ssa5IPk4egFaHtJ9zA3J8U78" frameBorder="0" allow="accelerometer:autoplay;encrypted-media; gyroscope; picture-in-picture" allowFullScreen></iframe>   
                        <figcaption style={{color: '#000', fontFamily: 'gameplay', fontWeight: '2em', textShadow: '0.08em 0.08em #8AAAB9'}}>
                            Flash Animations</figcaption> 
                </figure>
            </div>
            )
        }

    }
    export default Animation;