//React
import React from 'react';


//book images
import pastaBoss from '../../static/books/1.png'; 
import aColoringNightmare from '../../static/books/2.png';
import swankyVelvet from '../../static/books/3.png';


const bookLayout = {
    display: 'flex',
    flexDirection: 'row',
}


class Books extends React.Component{

    render(){

        return (
            <div >
            <figure className="books">
                <div style={bookLayout}>
                    <a className="image-gallery-link" href="https://www.amazon.com/dp/1691701394"> <img src={pastaBoss} alt="paperback book pastaboss"/></a>
                    <a className="image-gallery-link" href="https://www.amazon.com/dp/1691701394"> <img src={aColoringNightmare} alt="paperback coloring book"/></a>
                    <a className="image-gallery-link" href="https://www.amazon.com/dp/1797805428"> <img src={swankyVelvet} alt="paperback book swanky velvet" /></a>
                 </div>  
             <figcaption style={{color: '#000', fontFamily: 'gameplay', fontWeight: '2em', textShadow: '0.08em 0.08em #8AAAB9'}}
             >Paperbacks available on Amazon!</figcaption>
            </figure> 
            </div>
        )
        
    }

}

export default Books;