import React from 'react';
import ReactDOM from 'react-dom';
import './index.css';
import './bootstrap.min.css';
import App from './App';
import * as serviceWorker from './serviceWorker';

ReactDOM.render(<App />, document.getElementById('root'));
navigator.vibrate = navigator.vibrate || navigator.webkitVibrate || navigator.mozVibrate || navigator.msVibrate;

let header = document.getElementById('header'),
headerImg = document.getElementById('header-image');
// topNav = document.getElementById('top-nav'),
// bottomNav = document.getElementById('bottom-nav'),
// footer = document.getElementById('footer'),
// background = document.getElementsByClassName('background'),
// contentContainer = document.getElementsByClassName('content-container'),
// deviceStyle = document.getElementsByClassName('device-style'),
// videoGalleryLink = document.getElementsByClassName('video-gallery-link');

function checkSize (){
    window.screen.height > window.screen.width ? header.style.width = '100%' : headerImg.style.width = '50%';
} 
checkSize();
window.addEventListener('resize', checkSize, false);


// If you want your app to work offline and load faster, you can change
