import React from 'react';
//vector images
import vector1 from '../../static/vectors/thumbnails/1.png';
import vector2 from '../../static/vectors/thumbnails/2.png';
import vector3 from '../../static/vectors/thumbnails/3.png';
import vector4 from '../../static/vectors/thumbnails/4.png';



const vectorLayout = {
    display: 'grid',
    gridTemplateColumns: '1fr 1fr',
    gridGap: '1rem',
    alignItems: 'center'
}

class Vector extends React.Component{

 render(){
     return (
         <div>
             <figure className="image-gallery" style={vectorLayout}>
                <a className="image-gallery-link" href={vector1}> <img src={vector1} alt="vector illustration"/></a>
                <a className="image-gallery-link" href={vector2}> <img src={vector2} alt="vector illustration"/></a>
                <a className="image-gallery-link" href={vector3}> <img src={vector3} alt="vector illustration"/></a>
                <a className="image-gallery-link" href={vector4}> <img src={vector4} alt="vector illustration"/></a>
                <figcaption style={{color: '#000', fontFamily: 'gameplay', fontWeight: '2em', textShadow: '0.08em 0.08em #8AAAB9'}}>
                Vector Illustration </figcaption>
             </figure>
         </div>
        )  
    }
}
export default Vector;